import React from 'react';
import './EyePanel.css';

export default function EyePanel() {
  return (
    <div className="eye-wrap">
      {/* open eye underneath — fades in as lid lifts */}
      <img className="eye-img eye-open" src="/eye-open.svg" alt="" draggable={false} />
      {/* closed eye on top — upper lid clips away upward */}
      <img className="eye-img eye-closed" src="/eye-closed.svg" alt="" draggable={false} />
    </div>
  );
}
